class Solution:
    def minArea(self, image: List[List[str]], x: int, y: int) -> int:
        m, n = len(image), len(image[0])
        top = self.find_first_row_with_one(image, x, 0, x)
        bottom = self.find_last_row_with_one(image, x, x, m - 1)
        left = self.find_first_col_with_one(image, y, 0, y)
        right = self.find_last_col_with_one(image, y, y, n - 1)
        return (bottom - top + 1) * (right - left + 1)

    def find_first_row_with_one(self, image, x, start, end):
        while start <= end:
            mid = (start + end) // 2
            if any(cell == '1' for cell in image[mid]):
                end = mid - 1
            else:
                start = mid + 1
        return start

    def find_last_row_with_one(self, image, x, start, end):
        while start <= end:
            mid = (start + end) // 2
            if any(cell == '1' for cell in image[mid]):
                start = mid + 1
            else:
                end = mid - 1
        return end

    def find_first_col_with_one(self, image, y, start, end):
        while start <= end:
            mid = (start + end) // 2
            if any(image[i][mid] == '1' for i in range(len(image))):
                end = mid - 1
            else:
                start = mid + 1
        return start

    def find_last_col_with_one(self, image, y, start, end):
        while start <= end:
            mid = (start + end) // 2
            if any(image[i][mid] == '1' for i in range(len(image))):
                start = mid + 1
            else:
                end = mid - 1
        return end
