class Solution:
    def integerReplacement(self, n: int) -> int:
        count = 0
        while n != 1:
            if n % 2 == 0:
                n //= 2
            else:
                # Decide whether to add or subtract based on which path leads to fewer steps
                # For large n, adding 1 might be better if n is 3, but for n = 7, subtracting is better
                # The optimal choice can be determined by checking if n + 1 is divisible by 4 (which might lead to fewer steps)
                if n == 3 or (n + 1) % 4 == 0:
                    n += 1
                else:
                    n -= 1
            count += 1
        return count
