from typing import List

class Solution:
    def movesToChessboard(self, board: List[List[int]]) -> int:
        n = len(board)

        # Check if the board can be transformed into a chessboard
        # For a chessboard, each row must be the complement of the other
        # So, there should be exactly two types of rows: one with 0 in the first position and one with 1 in the first position
        # Similarly for columns

        # Check row conditions
        row1 = board[0]
        row2 = [1 - x for x in row1]

        # Count how many times each row appears
        row_count = {}
        for row in board:
            if tuple(row) in row_count:
                row_count[tuple(row)] += 1
            else:
                row_count[tuple(row)] = 1

        # For a valid chessboard, there should be exactly two types of rows, and their counts should be n//2 or n//2 + 1
        if len(row_count) != 2:
            return -1

        # Check if the rows are complements of each other
        if row1 != row2 and not all(row == row1 or row == row2 for row in board):
            return -1

        # Similarly for columns
        col1 = board[0]
        col2 = [1 - x for x in col1]

        col_count = {}
        for i in range(n):
            col = [board[j][i] for j in range(n)]
            if tuple(col) in col_count:
                col_count[tuple(col)] += 1
            else:
                col_count[tuple(col)] = 1

        if len(col_count) != 2:
            return -1

        # Check if the columns are complements of each other
        if col1 != col2 and not all(col == col1 or col == col2 for col in col_count):
            return -1

        # Now calculate the minimum number of moves
        # For rows: we need to find the minimum number of swaps to bring the correct rows to the correct positions
        # The correct rows are row1 and row2, and they must alternate
        # So, for each row, if it's not in the correct position, we need to swap it with the correct one

        # For rows
        row_moves = 0
        for i in range(n):
            if i % 2 == 0:
                if board[i] != row1:
                    # Find the first row that is row1 and is not in the correct position
                    for j in range(i + 1, n):
                        if board[j] == row1:
                            # Swap rows i and j
                            board[i], board[j] = board[j], board[i]
                            row_moves += 1
                            break
            else:
                if board[i] != row2:
                    # Find the first row that is row2 and is not in the correct position
                    for j in range(i + 1, n):
                        if board[j] == row2:
                            # Swap rows i and j
                            board[i], board[j] = board[j], board[i]
                            row_moves += 1
                            break

        # For columns
        col_moves = 0
        for i in range(n):
            if i % 2 == 0:
                if [board[j][i] for j in range(n)] != col1:
                    # Find the first column that is col1 and is not in the correct position
                    for j in range(i + 1, n):
                        if [board[j][i] for j in range(n)] == col1:
                            # Swap columns i and j
                            for k in range(n):
                                board[k][i], board[k][j] = board[k][j], board[k][i]
                            col_moves += 1
                            break
            else:
                if [board[j][i] for j in range(n)] != col2:
                    # Find the first column that is col2 and is not in the correct position
                    for j in range(i + 1, n):
                        if [board[j][i] for j in range(n)] == col2:
                            # Swap columns i and j
                            for k in range(n):
                                board[k][i], board[k][j] = board[k][j], board[k][i]
                            col_moves += 1
                            break

        return row_moves + col_moves
