from typing import List
import heapq

class Solution:
    def numberOfSets(self, n: int, maxDistance: int, roads: List[List[int]]) -> int:
        # Build the graph
        graph = [[] for _ in range(n)]
        for u, v, w in roads:
            graph[u].append((v, w))
            graph[v].append((u, w))

        # Function to check if a subset of nodes is valid
        def is_valid(subset):
            # Build adjacency list for the subset
            subset_graph = {node: [] for node in subset}
            for u, v, w in roads:
                if u in subset and v in subset:
                    subset_graph[u].append((v, w))
                    subset_graph[v].append((u, w))

            # Compute all-pairs shortest paths using Dijkstra's algorithm
            dist = {node: {other: float('inf') for other in subset} for node in subset}
            for node in subset:
                dist[node][node] = 0
                heap = [(0, node)]
                while heap:
                    d, u = heapq.heappop(heap)
                    if d > dist[node][u]:
                        continue
                    for v, w in subset_graph[u]:
                        if dist[node][v] > d + w:
                            dist[node][v] = d + w
                            heapq.heappush(heap, (dist[node][v], v))

            # Check if all pairs are within maxDistance
            for u in subset:
                for v in subset:
                    if u != v and dist[u][v] > maxDistance:
                        return False
            return True

        # Generate all subsets and count valid ones
        result = 0
        for mask in range(1 << n):
            subset = [i for i in range(n) if (mask & (1 << i))]
            if is_valid(subset):
                result += 1

        return result
