from typing import List
from collections import defaultdict

class Solution:
    def maxJumps(self, arr: List[int], d: int) -> int:
        n = len(arr)
        memo = [-1] * n  # memo[i] stores the max number of indices that can be visited starting from i

        def dfs(i):
            if memo[i] != -1:
                return memo[i]
            max_count = 1  # At least the current index
            # Check to the right
            for j in range(i + 1, min(i + d + 1, n)):
                if arr[i] <= arr[j]:
                    break
                max_count = max(max_count, 1 + dfs(j))
            # Check to the left
            for j in range(i - 1, max(i - d - 1, -1), -1):
                if arr[i] <= arr[j]:
                    break
                max_count = max(max_count, 1 + dfs(j))
            memo[i] = max_count
            return max_count

        return max(dfs(i) for i in range(n))
