from typing import List

class Solution:
    def maxTurbulenceSize(self, arr: List[int]) -> int:
        n = len(arr)
        if n == 1:
            return 1

        max_len = 2  # At least two elements are needed for turbulence

        for i in range(n - 1):
            # We will check two possible turbulence patterns starting at i
            # Pattern 1: up-down-up-down...
            # Pattern 2: down-up-down-up...

            # Try pattern 1: alternating starting with up (arr[i] < arr[i+1])
            length1 = 1
            for j in range(i, n - 1):
                if arr[j] < arr[j + 1]:
                    length1 += 1
                elif arr[j] > arr[j + 1]:
                    length1 += 1
                else:
                    break
            max_len = max(max_len, length1)

            # Try pattern 2: alternating starting with down (arr[i] > arr[i+1])
            length2 = 1
            for j in range(i, n - 1):
                if arr[j] > arr[j + 1]:
                    length2 += 1
                elif arr[j] < arr[j + 1]:
                    length2 += 1
                else:
                    break
            max_len = max(max_len, length2)

        return max_len

