class Solution:
    def canChange(self, start: str, target: str) -> bool:
        n = len(start)
        i = j = 0

        while i < n and j < n:
            if start[i] == target[j]:
                i += 1
                j += 1
            elif start[i] == '_':
                i += 1
            elif target[j] == '_':
                j += 1
            else:
                return False

        # Now check if the remaining characters in start and target match
        while i < n:
            if start[i] != '_':
                return False
            i += 1

        while j < n:
            if target[j] != '_':
                return False
            j += 1

        return True
