from typing import List

class Solution:
    def makesquare(self, matchsticks: List[int]) -> bool:
        total = sum(matchsticks)
        n = len(matchsticks)

        # If total length is not divisible by 4, it's impossible to form a square
        if total % 4 != 0:
            return False

        side = total // 4

        # If any stick is longer than the side length, it's impossible
        if any(stick > side for stick in matchsticks):
            return False

        # We will try to place each stick into one of the 4 sides
        # We use a backtracking approach with memoization to avoid redundant work
        # We'll use memoization with bitmask to represent used sticks

        from functools import lru_cache

        @lru_cache(maxsize=None)
        def backtrack(mask, sides):
            if mask == 0:
                return True
            # Try placing the current stick into each side
            for i in range(4):
                # Get the current stick
                stick = matchsticks[bin(mask).count('1')]
                # Check if the current side can take this stick
                if sides[i] + stick <= side:
                    # Place the stick in this side
                    new_sides = sides[:i] + (sides[i] + stick,) + sides[i+1:]
                    # Try to place the remaining sticks
                    if backtrack(mask ^ (1 << bin(mask).count('1')), new_sides):
                        return True
            return False

        # Initial state: all sides are 0
        return backtrack((1 << n) - 1, (0, 0, 0, 0))
