class Solution:
    def scoreOfParentheses(self, s: str) -> int:
        stack = []
        score = 0
        for char in s:
            if char == '(':
                stack.append(score)
                score = 0
            else:
                top = stack.pop()
                if score == 0:
                    score = 1
                else:
                    score = 2 * score + top
        return score
