class Solution:
    def findRotateSteps(self, ring: str, key: str) -> int:
        from collections import defaultdict

        n = len(ring)
        positions = defaultdict(list)
        for i, c in enumerate(ring):
            positions[c].append(i)

        # dp[i][pos] = min steps to reach key[i] with ring at position pos
        dp = [ [float('inf')] * n for _ in range(len(key)) ]

        # Initialize for the first character of key
        for pos in positions[key[0]]:
            dist = min(pos, n - pos)
            dp[0][pos] = dist + 1  # steps to rotate + press

        # Iterate over the key
        for i in range(1, len(key)):
            current_char = key[i]
            for curr_pos in positions[current_char]:
                for prev_pos in positions[key[i-1]]:
                    # Calculate rotation steps from prev_pos to curr_pos
                    clockwise = abs(curr_pos - prev_pos)
                    counter_clockwise = n - clockwise
                    steps = min(clockwise, counter_clockwise)
                    dp[i][curr_pos] = min(dp[i][curr_pos], dp[i-1][prev_pos] + steps + 1)

        return min(dp[-1])
