Here's a Python solution for the problem. The idea is to perform a BFS to determine the earliest time each cell is burned by fire. Then, we perform a BFS again to simulate the person's movement and determine the maximum time they can wait at the start before reaching the safehouse.

We use a binary search approach to find the maximum number of minutes the person can wait at the start (0, 0) and still reach the safehouse safely.

```python
from typing import List
from collections import deque

class Solution:
    def maximumMinutes(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])

        # Step 1: BFS to find the time when each cell is on fire
        fire_time = [[float('inf')] * n for _ in range(m)]
        q = deque()

        for i in range(m):
            for j in range(n):
                if grid[i][j] == 1:
                    fire_time[i][j] = 0
                    q.append((i, j))

        directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

        while q:
            x, y = q.popleft()
            for dx, dy in directions:
                nx, ny = x + dx, y + dy
                if 0 <= nx < m and 0 <= ny < n and grid[nx][ny] != 2 and fire_time[nx][ny] == float('inf'):
                    fire_time[nx][ny] = fire_time[x][y] + 1
                    q.append((nx, ny))

        # Check if the safehouse is reachable by fire
        def is_reachable(start_time):
            visited = [[False] * n for _ in range(m)]
            q = deque()
            q.append((0, 0, start_time))
            visited[0][0] = True

            while q:
                x, y, t = q.popleft()
                if x == m - 1 and y == n - 1:
                    return True
                for dx, dy in directions:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < m and 0 <= ny < n and grid[nx][ny] != 2 and not visited[nx][ny]:
                        if t + 1 < fire_time[nx][ny]:
                            visited[nx][ny] = True
                            q.append((nx, ny, t + 1))
            return False

        # Check if the start is blocked
        if grid[0][0] == 2 or grid[m-1][n-1] == 2:
            return -1

        # Check if the safehouse is reachable without any delay
        if is_reachable(0):
            # Binary search to find the maximum delay
            left, right = 0, 10**9
            answer = 0

            while left <= right:
                mid = (left + right) // 2
                if is_reachable(mid):
                    answer = mid
                    left = mid + 1
                else:
                    right = mid - 1

            if answer == 0:
                # Check if it's always possible to reach the safehouse
                if is_reachable(10**9):
                    return 10**9
                else:
                    return -1
            else:
                return answer
        else:
            return -1
```

This solution handles the problem efficiently using BFS and binary search to determine the maximum delay possible before the person can still reach the safehouse.

