class Solution:
    def beautifulSubstrings(self, s: str, k: int) -> int:
        vowels = set('aeiou')
        n = len(s)
        count = 0

        # Precompute prefix sums for vowels
        prefix_vowel = [0] * (n + 1)
        for i in range(n):
            prefix_vowel[i + 1] = prefix_vowel[i] + (1 if s[i] in vowels else 0)

        # Iterate over all possible substrings
        for i in range(n):
            for j in range(i + 1, n + 1):
                vowel_count = prefix_vowel[j] - prefix_vowel[i]
                consonant_count = (j - i) - vowel_count

                if vowel_count == consonant_count and (vowel_count * consonant_count) % k == 0:
                    count += 1

        return count
