class Solution:
    def singleNumber(self, nums: List[int]) -> List[int]:
        # Step 1: Compute the XOR of all numbers
        # This gives us xor_of_two = num1 ^ num2
        xor_of_two = 0
        for num in nums:
            xor_of_two ^= num

        # Step 2: Find a distinguishing bit (the rightmost set bit)
        # This bit is different between num1 and num2
        rightmost_set_bit = 1
        while (xor_of_two & rightmost_set_bit) == 0:
            rightmost_set_bit <<= 1

        # Step 3: Partition the numbers into two groups based on this bit
        # One group will contain num1, the other num2
        num1, num2 = 0, 0
        for num in nums:
            if num & rightmost_set_bit:
                num1 ^= num
            else:
                num2 ^= num

        return [num1, num2]
