class Solution:
    def isNumber(self, s: str) -> bool:
        # Check if the string is a valid number as per the problem's rules
        def is_integer(part):
            return part.isdigit() or (part.startswith('+') or part.startswith('-')) and part[1:].isdigit()

        def is_decimal(part):
            # Check if part is a decimal number
            if '.' not in part:
                return False
            parts = part.split('.')
            if len(parts) > 2:
                return False
            # Check the part before the dot
            if parts[0] == '':
                left = ''
            elif parts[0].startswith('+') or parts[0].startswith('-'):
                left = parts[0][1:]
            else:
                left = parts[0]
            if not left.isdigit():
                return False
            # Check the part after the dot
            if parts[1] == '':
                right = ''
            else:
                right = parts[1]
            return right.isdigit()

        def is_exponent(part):
            # Check if part is an integer (exponent part)
            return part.isdigit() or (part.startswith('+') or part.startswith('-')) and part[1:].isdigit()

        # Split the string into two parts on 'e' or 'E'
        parts = s.lower().split('e')
        if len(parts) > 2:
            return False

        # Check the first part (decimal or integer)
        if len(parts) == 1:
            return is_decimal(parts[0]) or is_integer(parts[0])
        else:
            # Check the first part is decimal or integer
            if not (is_decimal(parts[0]) or is_integer(parts[0])):
                return False
            # Check the second part is an integer
            return is_exponent(parts[1])

