        def is_palindrome(sub: str) -> bool:
            return sub == sub[::-1]

        # Find the longest prefix which is a palindrome
        n = len(s)
        for i in range(n, -1, -1):
            if is_palindrome(s[:i]):
                # Add the reverse of the remaining suffix to the front
                return s[i:][::-1] + s

        return s  # In case the entire string is a palindrome already
