class Solution:
    def countPairs(self, deliciousness: List[int]) -> int:
        MOD = 10**9 + 7
        from collections import defaultdict
        count = defaultdict(int)
        result = 0
        power_of_two = set()
        # Precompute all possible power of two sums up to 2^21 (since max sum is 2^20 + 2^20 = 2^21)
        for i in range(21):
            power_of_two.add(1 << i)

        for num in deliciousness:
            for p in power_of_two:
                complement = p - num
                if complement in count:
                    result += count[complement]
            count[num] += 1

        return result % MOD
