class Solution:
    def integerReplacement(self, n: int) -> int:
        count = 0
        while n != 1:
            if n % 2 == 0:
                n //= 2
            else:
                # Check which of n+1 or n-1 leads to fewer steps
                if n == 3:
                    n -= 1
                elif (n + 1) % 4 == 0:
                    n += 1
                else:
                    n -= 1
            count += 1
        return count

