from typing import List

class Solution:
    def canPartitionKSubsets(self, nums: List[int], k: int) -> bool:
        total = sum(nums)
        if total % k != 0:
            return False

        target = total // k
        nums.sort(reverse=True)  # Sort in descending order for efficiency

        used = [False] * len(nums)

        def backtrack(start, current_sum, count):
            if count == k:
                return True
            if current_sum == target:
                return backtrack(0, 0, count + 1)

            for i in range(start, len(nums)):
                if used[i]:
                    continue
                if current_sum + nums[i] > target:
                    continue
                if i > 0 and nums[i] == nums[i - 1] and not used[i - 1]:
                    continue  # Skip duplicates to avoid redundant work

                used[i] = True
                if backtrack(i, current_sum + nums[i], count):
                    return True
                used[i] = False

            return False

        return backtrack(0, 0, 0)

def run_tests():
    sol = Solution()
    print(sol.canPartitionKSubsets([4,3,2,3,5,2,1], 4))  # True
    print(sol.canPartitionKSubsets([1,2,3,4], 3))         # False

run_tests()
```

This solution uses backtracking with pruning to efficiently try to partition the array into `k` subsets with equal sums. The `run_tests()` function is included to test the solution with sample inputs.

