from typing import List

class Solution:
    def minDifficulty(self, jobDifficulty: List[int], d: int) -> int:
        n = len(jobDifficulty)
        if n < d:
            return -1

        # dp[i][j] represents the minimum difficulty to schedule the first i jobs in j days
        dp = [[float('inf')] * (d + 1) for _ in range(n + 1)]
        dp[0][0] = 0

        for i in range(1, n + 1):
            for j in range(1, d + 1):
                # Try to split the first i jobs into j days
                # k is the number of jobs done on the j-th day
                for k in range(j - 1, i):
                    # current day's difficulty is the max of jobs from k to i-1
                    current_max = max(jobDifficulty[k:i])
                    dp[i][j] = min(dp[i][j], dp[k][j - 1] + current_max)

        return dp[n][d] if dp[n][d] != float('inf') else -1
