class Solution:
    def numMagicSquaresInside(self, grid: List[List[int]]) -> int:
        rows = len(grid)
        cols = len(grid[0]) if rows > 0 else 0

        count = 0

        # Iterate over all possible top-left corners of 3x3 subgrids
        for i in range(rows - 2):
            for j in range(cols - 2):
                # Extract the 3x3 subgrid
                subgrid = [
                    [grid[i][j], grid[i][j+1], grid[i][j+2]],
                    [grid[i+1][j], grid[i+1][j+1], grid[i+1][j+2]],
                    [grid[i+2][j], grid[i+2][j+1], grid[i+2][j+2]]
                ]

                # Check if all numbers are distinct and in 1-9
                flat = [num for row in subgrid for num in row]
                if len(set(flat)) != 9 or any(num < 1 or num > 9 for num in flat):
                    continue

                # Check magic square conditions
                magic_sum = sum(subgrid[0])

                # Check rows
                for row in subgrid:
                    if sum(row) != magic_sum:
                        break
                else:
                    # Check columns
                    for col in range(3):
                        col_sum = subgrid[0][col] + subgrid[1][col] + subgrid[2][col]
                        if col_sum != magic_sum:
                            break
                    else:
                        # Check diagonals
                        diag1 = subgrid[0][0] + subgrid[1][1] + subgrid[2][2]
                        diag2 = subgrid[0][2] + subgrid[1][1] + subgrid[2][0]
                        if diag1 == magic_sum and diag2 == magic_sum:
                            count += 1
        return count
