        if not prefix:
            # If t is not a subsequence of s, return len(t)
            return len(t)
        if not suffix:
            # Only prefix is used, so the suffix is not used, so we need to remove the remaining
            return len(t) - len(prefix)

        # The idea is to find the smallest window where prefix[i] <= suffix[j] (i.e., the removed part is between prefix and suffix)
        # Iterate over possible positions of prefix and suffix
        min_score = float('inf')
        n = len(prefix)
