from typing import List

class Solution:
    def predictTheWinner(self, nums: List[int]) -> bool:
        # Helper function to determine if the current player can win from the subarray nums[left:right+1]
        def can_win(left, right):
            if left > right:
                return 0
            # Current player can choose either left or right element
            pick_left = nums[left] - can_win(left + 1, right)
            pick_right = nums[right] - can_win(left, right - 1)
            return max(pick_left, pick_right)

        # If the maximum score difference the first player can achieve is >= 0, player 1 wins
        return can_win(0, len(nums) - 1) >= 0

def run_tests():
    sol = Solution()
    print(sol.predictTheWinner([1,5,2]))   # Expected: False
    print(sol.predictTheWinner([1,5,233,7])) # Expected: True

run_tests()
