class Solution:
    def minimumCoins(self, prices: List[int]) -> int:
        n = len(prices)
        dp = [float('inf')] * (n + 1)  # dp[i] is the minimum coins needed to get the first i fruits

        # Base case: 0 fruits needed 0 coins
        dp[0] = 0

        for i in range(1, n + 1):
            # Option 1: Buy the i-th fruit (i-1 in 0-based)
            dp[i] = min(dp[i], dp[i - 1] + prices[i - 1])

            # Option 2: Take the i-th fruit for free if it's within the reward range of a previous purchase
            # We check all previous purchases to see if they can cover this fruit
            for j in range(i - 1, 0, -1):
                if dp[j] != float('inf'):
                    # If we bought the j-th fruit, we can take the next (j-1) fruits for free
                    # So if i <= j + (j - 1) => i <= 2j - 1
                    if i <= 2 * j - 1:
                        dp[i] = min(dp[i], dp[j])

        return dp[n]
