class Solution:
    def rectangleArea(self, rectangles: List[List[int]]) -> int:
        MOD = 10**9 + 7
        events = []
        for x1, y1, x2, y2 in rectangles:
            events.append((x1, y1, y2, 1))
            events.append((x2, y1, y2, -1))

        events.sort()
        res = 0
        active = set()
        prev_x = 0
        y_intervals = []

        for x, y1, y2, typ in events:
            if prev_x > 0:
                if active:
                    y_intervals.sort()
                    total_y = 0
                    for i in range(len(y_intervals) - 1):
                        total_y += y_intervals[i+1] - y_intervals[i]
                    res += (x - prev_x) * total_y
                    res %= MOD
            if typ == 1:
                active.add((y1, y2))
            else:
                active.remove((y1, y2))
            prev_x = x

        return res % MOD
