from typing import List

class Solution:
    def maxNumber(self, nums1: List[int], nums2: List[int], k: int) -> List[int]:
        def merge(a: List[int], b: List[int]) -> List[int]:
            merged = []
            i = j = 0
            while i < len(a) or j < len(b):
                if i < len(a) and (j >= len(b) or a[i] > b[j]):
                    merged.append(a[i])
                    i += 1
                else:
                    merged.append(b[j])
                    j += 1
            return merged

        def max_subsequence(nums: List[int], k: int) -> List[int]:
            stack = []
            for i, num in enumerate(nums):
                while stack and stack[-1] < num and len(stack) + len(nums) - i > k:
                    stack.pop()
                if len(stack) < k:
                    stack.append(num)
            return stack

        max_result = []
        for i in range(1, k + 1):
            if i <= len(nums1) and k - i <= len(nums2):
                candidate = merge(max_subsequence(nums1, i), max_subsequence(nums2, k - i))
                if candidate > max_result:
                    max_result = candidate
        return max_result
