from typing import List
from collections import defaultdict
from itertools import combinations

class Solution:
    def divisibleTripletCount(self, nums: List[int], d: int) -> int:
        # Count the frequency of each remainder when divided by d
        remainder_counts = defaultdict(int)
        for num in nums:
            remainder = num % d
            remainder_counts[remainder] += 1

        count = 0
        # Iterate over all possible triplets of remainders
        for r1, r2, r3 in combinations(remainder_counts.keys(), 3):
            if (r1 + r2 + r3) % d == 0:
                count += remainder_counts[r1] * remainder_counts[r2] * remainder_counts[r3]

        # Handle cases where two or all three remainders are the same
        # For two same remainders (r1 == r2)
        for r1, r2 in combinations(remainder_counts.keys(), 2):
            if r1 == r2:
                if (r1 + r1 + r3) % d == 0:
                    count += (remainder_counts[r1] * (remainder_counts[r1] - 1) // 2) * remainder_counts[r3]

        # For all three same remainders (r1 == r2 == r3)
        for r in remainder_counts:
            if (3 * r) % d == 0:
                count += (remainder_counts[r] * (remainder_counts[r] - 1) * (remainder_counts[r] - 2)) // 6

        return count
