class Solution:
    def sumCounts(self, nums: List[int]) -> int:
        MOD = 10**9 + 7
        n = len(nums)
        result = 0
        freq = {}

        for i in range(n):
            freq.clear()
            count = 0
            for j in range(i, n):
                if nums[j] not in freq:
                    count += 1
                    freq[nums[j]] = 1
                else:
                    freq[nums[j]] += 1
                result = (result + count * count) % MOD

        return result
