class Solution:
    def longestSubstring(self, s: str, k: int) -> int:
        def helper(s, k):
            if len(s) < k:
                return 0
            count = {}
            for c in s:
                count[c] = count.get(c, 0) + 1
            for c in count:
                if count[c] < k:
                    # Split the string on this character and recurse
                    return max(helper(part, k) for part in s.split(c))
            # If all characters meet the frequency requirement
            return len(s)

        return helper(s, k)
