class Solution:
    def minimumIndex(self, nums: List[int]) -> int:
        # Find the dominant element of the entire array
        total_count = {}
        for num in nums:
            total_count[num] = total_count.get(num, 0) + 1

        dominant = None
        for key, value in total_count.items():
            if value * 2 > len(nums):
                dominant = key
                break

        # Find the minimum index where both subarrays have the same dominant element
        n = len(nums)
        left_count = {}
        right_count = {}

        # Initialize right_count with the full array counts
        for num in nums:
            right_count[num] = right_count.get(num, 0) + 1

        for i in range(n - 1):
            # Update left_count
            left_num = nums[i]
            left_count[left_num] = left_count.get(left_num, 0) + 1
            # Update right_count
            right_num = nums[i + 1]
            right_count[right_num] = right_count.get(right_num, 0) - 1

            # Check if both subarrays have the same dominant element
            left_dom = None
            for key, value in left_count.items():
                if value * 2 > (i + 1):
                    left_dom = key
                    break

            right_dom = None
            for key, value in right_count.items():
                if value * 2 > (n - i - 1):
                    right_dom = key
                    break

            if left_dom == dominant and right_dom == dominant:
                return i

        return -1
