class Solution:
    def smallestString(self, s: str) -> str:
        s = list(s)
        n = len(s)
        i = 0

        # Find the first non-'a' character to start the operation
        while i < n and s[i] == 'a':
            i += 1

        # If all are 'a's, replace the last 'a' with 'z'
        if i == n:
            s[-1] = 'z'
            return ''.join(s)

        # Perform the operation on the substring from i to end of the run of non-'a's
        while i < n and s[i] != 'a':
            s[i] = chr(ord(s[i]) - 1)
            i += 1

        return ''.join(s)
