from collections import Counter

class Solution:
    def minSteps(self, s: str, t: str) -> int:
        count_s = Counter(s)
        count_t = Counter(t)

        # Calculate the difference in character counts
        diff = Counter()
        for char in count_s:
            diff[char] = count_s[char] - count_t.get(char, 0)
        for char in count_t:
            if count_t[char] > count_s.get(char, 0):
                diff[char] = count_t[char] - count_s.get(char, 0)

        # Sum up the absolute differences to get the total steps needed
        return sum(abs(val) for val in diff.values())
