from typing import List

class Solution:
    def largestMagicSquare(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])
        max_k = 1  # At least 1x1 is always a magic square

        # Precompute prefix sums for rows and columns
        row_prefix = [[0] * (n + 1) for _ in range(m)]
        col_prefix = [[0] * (m + 1) for _ in range(n)]

        for i in range(m):
            for j in range(n):
                row_prefix[i][j + 1] = row_prefix[i][j] + grid[i][j]
        for j in range(n):
            for i in range(m):
                col_prefix[j][i + 1] = col_prefix[j][i] + grid[i][j]

        # Try all possible square sizes from largest to smallest
        for k in range(min(m, n), 0, -1):
            for i in range(m - k + 1):
                for j in range(n - k + 1):
                    # Check if the subgrid from (i,j) to (i+k-1, j+k-1) is a magic square
                    if self.is_magic_square(grid, row_prefix, col_prefix, i, j, k, m, n):
                        return k
        return max_k

    def is_magic_square(self, grid, row_prefix, col_prefix, x, y, k, m, n):
        # Check row sums
        target_sum = 0
        for i in range(x, x + k):
            target_sum = row_prefix[i][y + k] - row_prefix[i][y]
            if target_sum != row_prefix[x][y + k] - row_prefix[x][y]:
                return False

        # Check column sums
        for j in range(y, y + k):
            col_sum = col_prefix[j][x + k] - col_prefix[j][x]
            if col_sum != target_sum:
                return False

        # Check diagonal sums
        diag1 = 0
        diag2 = 0
        for i in range(k):
            diag1 += grid[x + i][y + i]
            diag2 += grid[x + i][y + k - 1 - i]
        if diag1 != target_sum or diag2 != target_sum:
            return False

        return True
