class Solution:
    def longestBeautifulSubstring(self, word: str) -> int:
        max_len = 0
        n = len(word)
        i = 0
        vowels = {'a', 'e', 'i', 'o', 'u'}
        order = ['a', 'e', 'i', 'o', 'u']

        while i < n:
            if word[i] not in vowels:
                i += 1
                continue
            # Start of a potential beautiful substring
            start = i
            prev_char = word[i]
            count = 1
            i += 1
            while i < n:
                curr_char = word[i]
                if curr_char < prev_char:
                    # Not in order, reset
                    break
                elif curr_char == prev_char:
                    count += 1
                else:
                    # curr_char > prev_char, check if it's the next in order
                    if order.index(curr_char) == order.index(prev_char) + 1:
                        count += 1
                        prev_char = curr_char
                    else:
                        break
                i += 1
            # Check if all vowels are present in this substring
            unique_chars = set(word[start:i])
            if len(unique_chars) == 5:
                max_len = max(max_len, i - start)
        return max_len
