class Solution:
    def stoneGameVI(self, aliceValues: List[int], bobValues: List[int]) -> int:
        # Combine the values and sort by the sum of Alice's and Bob's values in descending order
        stones = sorted(zip(aliceValues, bobValues), key=lambda x: x[0] + x[1], reverse=True)

        alice_total = 0
        bob_total = 0

        for i, (alice_val, bob_val) in enumerate(stones):
            if i % 2 == 0:
                alice_total += alice_val
            else:
                bob_total += bob_val

        if alice_total > bob_total:
            return 1
        elif alice_total < bob_total:
            return -1
        else:
            return 0
