class Solution:
    def smallestNumber(self, num: int) -> int:
        if num >= 0:
            # For positive numbers, we want the smallest number without leading zeros
            digits = list(str(num))
            digits.sort()
            # Find the first non-zero digit to swap with the first position
            for i in range(len(digits)):
                if digits[i] != '0':
                    digits[0], digits[i] = digits[i], digits[0]
                    break
            return int(''.join(digits))
        else:
            # For negative numbers, we want the largest absolute value (i.e., most negative)
            digits = list(str(num)[1:])
            digits.sort(reverse=True)
            return -int(''.join(digits))
