class Solution:
    def goodBinaryStrings(self, minLength: int, maxLength: int, oneGroup: int, zeroGroup: int) -> int:
        MOD = 10**9 + 7

        # Memoization cache for dynamic programming
        from functools import lru_cache

        @lru_cache(None)
        def dp(length):
            if length == 0:
                return 1  # empty string
            res = 0
            # Add a block of 1s of size oneGroup
            if length >= oneGroup:
                res += dp(length - oneGroup)
            # Add a block of 0s of size zeroGroup
            if length >= zeroGroup:
                res += dp(length - zeroGroup)
            return res % MOD

        # Compute total number of good strings of length from minLength to maxLength
        total = 0
        for length in range(minLength, maxLength + 1):
            total = (total + dp(length)) % MOD
        return total
