from typing import List
from collections import defaultdict

class Solution:
    def constructDistancedSequence(self, n: int) -> List[int]:
        # The total length of the sequence is 2 * n - 1
        total_length = 2 * n - 1
        result = [0] * total_length
        used = [False] * (n + 1)  # 1-based indexing for numbers 1 to n

        def backtrack(pos):
            if pos == total_length:
                return True
            if result[pos] != 0:
                return backtrack(pos + 1)

            # Try to place the largest possible number at this position
            for i in range(n, 0, -1):
                if used[i]:
                    continue
                # If we are placing the first occurrence of i
                if result[pos] == 0:
                    # Check if placing i here is valid
                    # We need to make sure that the second occurrence of i is at pos + i
                    if pos + i >= total_length:
                        continue
                    if result[pos + i] != 0:
                        continue
                    # Place i at pos and pos + i
                    result[pos] = i
                    result[pos + i] = i
                    used[i] = True
                    if backtrack(pos + 1):
                        return True
                    # Backtrack
                    result[pos] = 0
                    result[pos + i] = 0
                    used[i] = False
            return False

        backtrack(0)
        return result
