from typing import List

class Solution:
    def largestCombination(self, candidates: List[int]) -> int:
        # For each bit position (0 to 30), count how many numbers in candidates have that bit set
        max_bit = 30  # since candidates[i] <= 1e7, which is less than 2^24, so 30 is safe
        bit_counts = [0] * (max_bit + 1)

        for num in candidates:
            for i in range(max_bit + 1):
                if num & (1 << i):
                    bit_counts[i] += 1

        # The maximum count of any bit set across all numbers is the answer
        return max(bit_counts)

