from typing import List

class Solution:
    def validateBinaryTreeNodes(self, n: int, leftChild: List[int], rightChild: List[int]) -> bool:
        # Check for invalid child references (node numbers must be in range)
        for i in range(n):
            if leftChild[i] != -1 and leftChild[i] >= n:
                return False
            if rightChild[i] != -1 and rightChild[i] >= n:
                return False

        # Check for multiple parents (each node can have only one parent)
        parent = [-1] * n
        for i in range(n):
            if leftChild[i] != -1:
                if parent[leftChild[i]] != -1:
                    return False
                parent[leftChild[i]] = i
            if rightChild[i] != -1:
                if parent[rightChild[i]] != -1:
                    return False
                parent[rightChild[i]] = i

        # There must be exactly one root (node with no parent)
        root_count = 0
        for i in range(n):
            if parent[i] == -1:
                root_count += 1
        if root_count != 1:
            return False

        # Check for cycles (we can do BFS or DFS from the root)
        # First, find the root
        root = -1
        for i in range(n):
            if parent[i] == -1:
                root = i
                break

        # If root is not found, it’s invalid
        if root == -1:
            return False

        # Use BFS to check for cycles
        visited = set()
        queue = [root]
        visited.add(root)

        while queue:
            current = queue.pop(0)
            for child in [leftChild[current], rightChild[current]]:
                if child == -1:
                    continue
                if child in visited:
                    return False
                visited.add(child)
                queue.append(child)

        # If all nodes are visited and no cycles, it's a valid tree
        if len(visited) != n:
            return False

        return True

# Function to run tests (for testing purposes only)
def run_tests():
    # Example 1
    print(Solution().validateBinaryTreeNodes(4, [1,-1,3,-1], [2,-1,-1,-1]))  # True
    # Example 2
    print(Solution().validateBinaryTreeNodes(4, [1,-1,3,-1], [2,3,-1,-1]))  # False
    # Example 3
    print(Solution().validateBinaryTreeNodes(2, [1,0], [-1,-1]))  # False

# Run the tests
run_tests()
