class Solution:
    def longestDecomposition(self, text: str) -> int:
        n = len(text)
        left = 0
        right = n - 1
        res = 0
        while left <= right:
            if text[left] == text[right]:
                # Try to match the smallest possible prefix and suffix
                match = False
                for i in range(1, right - left + 1):
                    if text[left:left+i] == text[right-i+1:right+1]:
                        res += 2
                        left += i
                        right -= i
                        match = True
                        break
                if not match:
                    # No match found, increment left and decrement right
                    left += 1
                    right -= 1
            else:
                left += 1
                right -= 1
        return res + (1 if left > right else 0)
