class Solution:
    def maxOperations(self, s: str) -> int:
        count = 0
        i = 0
        n = len(s)

        while i < n - 1:
            if s[i] == '1' and s[i + 1] == '0':
                # Move the '1' to the right until it hits another '1' or the end
                j = i
                while j + 1 < n and s[j + 1] == '0':
                    j += 1
                # The number of '0's between i and j is (j - i)
                count += 1
                # Move the '1' to the right by (j - i) positions
                i = j + 1
            else:
                i += 1

        return count
