# Precompute primes up to 1000 (max possible nums[i] is 1000)
def sieve(n):
    is_prime = [True] * (n + 1)
    is_prime[0] = is_prime[1] = False
    for i in range(2, int(n ** 0.5) + 1):
        if is_prime[i]:
            for j in range(i*i, n+1, i):
                is_prime[j] = False
    primes = [i for i, val in enumerate(is_prime) if val]
    return primes

primes = sieve(1000)

class Solution:
    def primeSubOperation(self, nums: List[int]) -> bool:
        # For each number, try to subtract a prime such that the resulting number is strictly greater than previous
        prev = -1
        for num in nums:
            # Try to subtract a prime p such that num - p > prev
            # Try all possible primes less than num
            for p in primes:
                if p >= num:
                    break
                if num - p > prev:
                    prev = num - p
                    break
            else:
                # No prime found, try subtracting nothing (i.e., no operation)
                if num > prev:
                    prev = num
                else:
                    return False
        return True

