class Solution:
    def numberOfPowerfulInt(self, start: int, finish: int, limit: int, s: str) -> int:
        from math import log10, floor

        def is_valid(num_str):
            return all(int(c) <= limit for c in num_str)

        def count_powerful_numbers():
            total = 0
            len_s = len(s)
            max_len = len(str(finish))
            min_len = len(str(start))

            for length in range(len_s, max_len + 1):
                # Generate all prefixes of length (length - len_s)
                # such that when we append s, the resulting number is in [start, finish]
                prefix_length = length - len_s
                if prefix_length < 0:
                    continue

                # Generate all possible prefixes
                for prefix in range(10 ** (prefix_length - 1), 10 ** prefix_length):
                    prefix_str = str(prefix)
                    if not is_valid(prefix_str):
                        continue
                    num_str = prefix_str + s
                    num = int(num_str)
                    if start <= num <= finish:
                        total += 1

                # Also consider prefix_length = 0 (i.e., the number is exactly s)
                if prefix_length == 0:
                    num = int(s)
                    if start <= num <= finish:
                        total += 1

            return total

        # Handle edge case when s is longer than finish
        if len(s) > len(str(finish)):
            return 0

        # Handle case when s is exactly in the range
        if start <= int(s) <= finish and is_valid(s):
            return 1

        # Count all valid numbers with length >= len(s)
        return count_powerful_numbers()
