completion:
Here's the solution using a monotonic stack approach. The idea is to find, for each element, the nearest greater element to the left and right. The length of the subarray where the current element is the maximum is then determined by the distance between these two elements.

This approach ensures that we efficiently find the maximum subarray length for each element in linear time.

```python
from typing import List

class Solution:
    def maximumLengthOfRanges(self, nums: List[int]) -> List[int]:
        n = len(nums)
        ans = [1] * n

        # Next greater to the right
        next_greater_right = [n] * n
        stack = []
        for i in range(n - 1, -1, -1):
            while stack and nums[stack[-1]] <= nums[i]:
                stack.pop()
            if stack:
                next_greater_right[i] = stack[-1]
            else:
                next_greater_right[i] = n
            stack.append(i)

        # Next greater to the left
        next_greater_left = [-1] * n
        stack = []
        for i in range(n):
            while stack and nums[stack[-1]] <= nums[i]:
                stack.pop()
            if stack:
                next_greater_left[i] = stack[-1]
            else:
                next_greater_left[i] = -1
            stack.append(i)

        # Calculate the answer
        for i in range(n):
            length = next_greater_right[i] - next_greater_left[i] - 1
            ans[i] = length

        return ans
