from typing import List
from collections import Counter

class Solution:
    def findPairs(self, nums: List[int], k: int) -> int:
        if k < 0:
            return 0
        count = Counter(nums)
        result = 0
        if k == 0:
            # For k = 0, count how many numbers appear at least twice
            for num in count:
                if count[num] >= 2:
                    result += 1
        else:
            # For k > 0, check if num + k exists in the counter
            for num in count:
                if (num + k) in count:
                    result += 1
        return result
