    def maxArrayValue(self, nums: List[int]) -> int:
        max_val = nums[-1]
        current = nums[-1]

        for i in range(len(nums) - 2, -1, -1):
            if nums[i] <= current:
                current += nums[i]
            else:
                current = nums[i]
            max_val = max(max_val, current)

        return max_val
