class Solution:
    def numberOfWays(self, corridor: str) -> int:
        MOD = 10**9 + 7
        seats = []
        for i, c in enumerate(corridor):
            if c == 'S':
                seats.append(i)

        if len(seats) % 2 != 0:
            return 0

        n = len(seats)
        result = 1
        for i in range(1, n, 2):
            # Number of ways to place a divider between the i-th and (i+1)-th seat
            # is the number of positions between seats[i-1] and seats[i]
            # but we can only place a divider after the second seat in each pair
            # so between seats[i] and seats[i+1]
            # So the number of ways is (seats[i+1] - seats[i])
            # but we need to calculate the product of these choices
            if i + 1 < n:
                result = (result * (seats[i+1] - seats[i])) % MOD

        return result
