class Solution:
    def getSmallestString(self, s: str, k: int) -> str:
        def distance(s1, s2):
            return sum(min(abs(ord(c1) - ord(c2)), 26 - abs(ord(c1) - ord(c2))) for c1, c2 in zip(s1, s2))

        def get_smallest(s, k):
            chars = list(s)
            n = len(s)
            for i in range(n):
                # Try to change current character to the smallest possible (from 'a' to current char)
                for c in range(ord('a'), ord(chars[i])):
                    new_char = chr(c)
                    new_k = distance(s, ''.join([new_char] + chars[1:]))
                    if new_k <= k:
                        chars[i] = new_char
                        k -= distance(s, ''.join([new_char] + chars[1:]))
                        break
            return ''.join(chars)

        return get_smallest(s, k)

