from typing import List

class Solution:
    def findPeakGrid(self, mat: List[List[int]]) -> List[int]:
        m, n = len(mat), len(mat[0])

        # We will use binary search on the columns
        # We'll search for a peak in O(m log n) time

        # Define a helper function to find the maximum in a column
        def get_max_col(col: int) -> int:
            max_val = mat[0][col]
            max_row = 0
            for i in range(1, m):
                if mat[i][col] > max_val:
                    max_val = mat[i][col]
                    max_row = i
            return max_row, max_val

        # Define a helper function to check if a cell is a peak
        def is_peak(i: int, j: int) -> bool:
            # Check all four directions
            # We assume the matrix is surrounded by -1
            if i > 0 and mat[i-1][j] >= mat[i][j]:
                return False
            if i < m - 1 and mat[i+1][j] >= mat[i][j]:
                return False
            if j > 0 and mat[i][j-1] >= mat[i][j]:
                return False
            if j < n - 1 and mat[i][j+1] >= mat[i][j]:
                return False
            return True

        # Binary search on columns
        left, right = 0, n - 1
        while left <= right:
            mid = (left + right) // 2
            # Find the row with the maximum value in column mid
            row, _ = get_max_col(mid)
            # Check if this is a peak
            if is_peak(row, mid):
                return [row, mid]
            # Otherwise, move towards the side where a peak must exist
            # Compare with the value to the left and right
            if mid > 0 and mat[row][mid - 1] > mat[row][mid]:
                right = mid - 1
            else:
                left = mid + 1
