from typing import List
from collections import Counter

class Solution:
    def wordSubsets(self, words1: List[str], words2: List[str]) -> List[str]:
        # Create a merged frequency counter for words2
        max_freq = Counter()
        for word in words2:
            word_counter = Counter(word)
            for char, count in word_counter.items():
                max_freq[char] = max(max_freq[char], count)

        # Check each word in words1 against the max_freq
        result = []
        for word in words1:
            word_counter = Counter(word)
            is_universal = True
            for char, required_count in max_freq.items():
                if word_counter.get(char, 0) < required_count:
                    is_universal = False
                    break
            if is_universal:
                result.append(word)

        return result
