from typing import List

class Solution:
    def isSelfCrossing(self, distance: List[int]) -> bool:
        n = len(distance)
        if n < 4:
            return False

        # We check for the first possible crossing
        # Case 1: current line crosses the line 3 steps back
        for i in range(3, n):
            if distance[i] >= distance[i - 2] and distance[i - 1] <= distance[i - 3]:
                return True

        # Case 2: current line crosses the line 4 steps back
        for i in range(4, n):
            if distance[i - 1] == distance[i - 3] and distance[i] + distance[i - 4] >= distance[i - 2]:
                return True

        # Case 3: current line crosses the line 5 steps back
        for i in range(5, n):
            if distance[i - 2] >= distance[i - 4] and distance[i - 3] >= distance[i - 5]:
                if distance[i] + distance[i - 4] >= distance[i - 2] and distance[i - 1] + distance[i - 5] >= distance[i - 3]:
                    return True

        return False

# Example test cases
def run_tests():
    sol = Solution()
    print(sol.isSelfCrossing([2,1,1,2]))  # Expected: True
    print(sol.isSelfCrossing([1,2,3,4]))  # Expected: False
    print(sol.isSelfCrossing([1,1,1,2,1]))  # Expected: True
