from typing import List

class Solution:
    def maximumGap(self, nums: List[int]) -> int:
        n = len(nums)
        if n < 2:
            return 0

        # Find min and max of the array
        min_num = min(nums)
        max_num = max(nums)

        # Calculate the bucket size
        bucket_size = (max_num - min_num) // n + 1
        if bucket_size == 0:
            return max_num - min_num

        # Initialize buckets
        buckets = [None] * n

        for num in nums:
            # Determine which bucket the number belongs to
            index = (num - min_num) // bucket_size
            if buckets[index] is None:
                buckets[index] = {'min': num, 'max': num}
            else:
                buckets[index]['min'] = min(buckets[index]['min'], num)
                buckets[index]['max'] = max(buckets[index]['max'], num)

        # Traverse buckets to find max gap
