class Solution:
    def rearrangeString(self, s: str, k: int) -> str:
        from collections import Counter
        import heapq

        if k == 0:
            return s

        count = Counter(s)
        max_heap = []
        for char, freq in count.items():
            heapq.heappush(max_heap, (-freq, char))

        result = []
        prev_char = None
        while max_heap:
            freq, char = heapq.heappop(max_heap)
            if char == prev_char:
                return ""
            result.append(char)
            prev_char = char
            freq += 1
            if freq < 0:
                heapq.heappush(max_heap, (freq, char))
            # Wait for k steps
            for _ in range(k - 1):
                if max_heap:
                    next_freq, next_char = heapq.heappop(max_heap)
                    if next_char == prev_char:
                        return ""
                    result.append(next_char)
                    prev_char = next_char
                    next_freq += 1
                    if next_freq < 0:
                        heapq.heappush(max_heap, (next_freq, next_char))
                else:
                    return ""

        return ''.join(result)
