class Solution:
    def numberOfPairs(self, points: List[List[int]]) -> int:
        n = len(points)
        count = 0

        for i in range(n):
            for j in range(n):
                if i == j:
                    continue
                # Check if Alice (i) is upper left and Bob (j) is lower right
                # Alice's x <= Bob's x and Alice's y >= Bob's y
                if points[i][0] <= points[j][0] and points[i][1] >= points[j][1]:
                    # Check if any other point is inside or on the rectangle
                    valid = True
                    for k in range(n):
                        if k == i or k == j:
                            continue
                        x, y = points[k]
                        # Check if point (x, y) is inside or on the rectangle
                        if (points[i][0] <= x <= points[j][0] and points[j][1] <= y <= points[i][1]):
                            valid = False
                            break
                    if valid:
                        count += 1
        return count
