class Solution:
    def largestSubmatrix(self, matrix: List[List[int]]) -> int:
        m, n = len(matrix), len(matrix[0])

        # Step 1: Convert the matrix into a histogram matrix
        for i in range(m):
            for j in range(n):
                if matrix[i][j] == 1 and i > 0:
                    matrix[i][j] += matrix[i-1][j]
                else:
                    matrix[i][j] = matrix[i][j]

        # Step 2: For each row, sort the row in descending order and calculate the max area
        max_area = 0
        for i in range(m):
            row = matrix[i][:]
            row.sort(reverse=True)
            for j in range(n):
                max_area = max(max_area, row[j] * (j + 1))

        return max_area
