class Solution:
    def lengthOfLongestSubsequence(self, nums: List[int], target: int) -> int:
        # We use dynamic programming to track the maximum length of subsequences that sum to a certain value.
        # dp[i] will store the maximum length of a subsequence that sums up to i.
        dp = [-1] * (target + 1)
        dp[0] = 0  # Base case: sum of 0 can be achieved with 0 elements.

        for num in nums:
            # We iterate backwards to avoid reusing the same number multiple times in the same step
            for i in range(target, num - 1, -1):
                if dp[i - num] != -1:
                    dp[i] = max(dp[i], dp[i - num] + 1)

        return dp[target] if dp[target] != -1 else -1
