class Solution:
    def maximumSubsequenceCount(self, text: str, pattern: str) -> int:
        # Count the number of occurrences of each character in the pattern in the text
        count_pattern = {pattern[0]: 0, pattern[1]: 0}
        for char in text:
            if char == pattern[0]:
                count_pattern[pattern[0]] += 1
            elif char == pattern[1]:
                count_pattern[pattern[1]] += 1

        # Calculate the initial number of subsequences
        total = 0
        for i, char in enumerate(text):
            if char == pattern[1]:
                total += count_pattern[pattern[0]]

        # Now, consider adding pattern[0] or pattern[1] to maximize the count
        # Adding pattern[0]: it can contribute to all subsequent occurrences of pattern[1]
        max_add_0 = count_pattern[pattern[1]]

        # Adding pattern[1]: it can contribute to all previous occurrences of pattern[0]
        max_add_1 = count_pattern[pattern[0]]

        # The maximum possible is the initial total plus the maximum of the two additions
        return total + max(max_add_0, max_add_1)
