class Solution:
    def deleteString(self, s: str) -> int:
        n = len(s)
        dp = [1] * n  # dp[i] will store the maximum number of operations starting from index i

        # We'll iterate from the end to the beginning
        for i in range(n - 2, -1, -1):
            # Check for all possible i such that s[i:i + j] == s[i + j:i + 2j]
            # j is the length of the substring to delete
            for j in range(1, (n - i) // 2 + 1):
                if s[i:i + j] == s[i + j:i + 2 * j]:
                    dp[i] = max(dp[i], 1 + dp[i + j])

        return dp[0]
