class Solution:
    def minimumWhiteTiles(self, floor: str, numCarpets: int, carpetLen: int) -> int:
        n = len(floor)
        dp = [[0] * (numCarpets + 1) for _ in range(n + 1)]

        for i in range(n):
            for k in range(numCarpets + 1):
                # Case 1: Do not place a carpet ending at position i
                dp[i + 1][k] = dp[i][k] + (1 if floor[i] == '1' else 0)

                # Case 2: Place a carpet ending at position i (if possible)
                if k > 0 and i >= carpetLen - 1:
                    # Calculate the number of white tiles covered by placing a carpet ending at i
                    covered = 0
                    for j in range(i - carpetLen + 1, i + 1):
                        if floor[j] == '1':
                            covered += 1
                    dp[i + 1][k] = min(dp[i + 1][k], dp[i - carpetLen + 1][k - 1] + (covered - (1 if floor[i] == '1' else 0)))

        return dp[n][numCarpets]
