from typing import List

class Solution:
    def minOperations(self, nums: List[int]) -> int:
        count = Counter(nums)
        operations = 0

        for key in count:
            if count[key] == 1:
                operations += 1
            elif count[key] % 2 == 0:
                operations += count[key] // 2
            else:
                operations += (count[key] // 2) + 1

        return operations
